/* ═══════════════════════════════════════════════════════════════
   FONTS & GLOBAL STYLES
═══════════════════════════════════════════════════════════════ */
const injectStyles = () => {
  const link = document.createElement("link");
  link.rel = "stylesheet";
  link.href = "https://fonts.googleapis.com/css2?family=Cormorant+Garamond:ital,wght@0,300;0,400;0,600;1,300;1,400;1,600&family=Jost:wght@200;300;400;500;600&family=Playfair+Display:ital,wght@0,400;0,700;1,400&display=swap";
  document.head.appendChild(link);

  const style = document.createElement("style");
  style.textContent = `
    *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
    body { overflow-x: hidden; }
    @keyframes fadeUp { from{opacity:0;transform:translateY(20px)} to{opacity:1;transform:translateY(0)} }
    @keyframes fadeIn { from{opacity:0} to{opacity:1} }
    @keyframes shimmer { 0%,100%{opacity:.5} 50%{opacity:1} }
    @keyframes float { 0%,100%{transform:translateY(0) rotate(0deg)} 50%{transform:translateY(-12px) rotate(2deg)} }
    @keyframes float2 { 0%,100%{transform:translateY(0) rotate(0deg)} 50%{transform:translateY(-8px) rotate(-1.5deg)} }
    @keyframes spin3d { from{transform:rotateY(0deg)} to{transform:rotateY(360deg)} }
    @keyframes glow { 0%,100%{box-shadow:0 0 20px rgba(192,25,44,0.3)} 50%{box-shadow:0 0 40px rgba(192,25,44,0.6),0 0 60px rgba(201,153,42,0.2)} }
    @keyframes slideIn { from{transform:translateX(100%)} to{transform:translateX(0)} }
    @keyframes slideUp { from{transform:translateY(100%);opacity:0} to{transform:translateY(0);opacity:1} }
    @keyframes pulse { 0%,100%{transform:scale(1)} 50%{transform:scale(1.05)} }
    @keyframes particles { 0%{transform:translateY(0) translateX(0) scale(1);opacity:1} 100%{transform:translateY(-80px) translateX(var(--dx)) scale(0);opacity:0} }
    @keyframes orb { 0%{transform:translate(0,0) scale(1)} 33%{transform:translate(30px,-20px) scale(1.1)} 66%{transform:translate(-20px,15px) scale(0.95)} 100%{transform:translate(0,0) scale(1)} }
    @keyframes cardEntrance { from{opacity:0;transform:translateY(30px) scale(0.95)} to{opacity:1;transform:translateY(0) scale(1)} }
    @keyframes toast { 0%{opacity:0;transform:translateY(20px)} 15%,85%{opacity:1;transform:translateY(0)} 100%{opacity:0;transform:translateY(-10px)} }

    /* ── PAGE LOADER ── */
    @keyframes loaderSpin { to { transform: rotate(360deg); } }
    @keyframes loaderPulse { 0%,100%{opacity:1;transform:scale(1)} 50%{opacity:0.4;transform:scale(0.85)} }
    @keyframes loaderFadeOut { 0%{opacity:1;pointer-events:all} 80%{opacity:1} 100%{opacity:0;pointer-events:none} }
    @keyframes loaderDot { 0%,80%,100%{transform:scale(0)} 40%{transform:scale(1)} }

    .page-loader {
      position: fixed; inset: 0; z-index: 9999;
      background: linear-gradient(160deg, #1a0008 0%, #0c0608 50%, #100410 100%);
      display: flex; flex-direction: column;
      align-items: center; justify-content: center; gap: 20px;
      animation: loaderFadeOut 0.4s ease 0.7s forwards;
    }
    .loader-ring {
      width: 56px; height: 56px; border-radius: 50%;
      border: 2px solid rgba(192,25,44,0.12);
      border-top-color: #c0192c;
      border-right-color: rgba(201,153,42,0.5);
      animation: loaderSpin 0.9s cubic-bezier(0.6,0.2,0.4,0.8) infinite;
    }
    .loader-inner {
      position: absolute; width: 36px; height: 36px; border-radius: 50%;
      border: 1.5px solid rgba(201,153,42,0.12);
      border-bottom-color: rgba(201,153,42,0.7);
      animation: loaderSpin 1.2s cubic-bezier(0.6,0.2,0.4,0.8) reverse infinite;
    }
    .loader-center-dot {
      position: absolute; width: 8px; height: 8px; border-radius: 50%;
      background: linear-gradient(135deg, #c0192c, #c9992a);
      animation: loaderPulse 1s ease infinite;
    }
    .loader-text {
      font-family: 'Cormorant Garamond', serif;
      font-size: 15px; font-style: italic; letter-spacing: 0.25em;
      color: rgba(242,221,226,0.5); text-transform: uppercase;
      animation: shimmer 1.5s ease infinite;
    }

    /* ── STATUS BADGE BUTTONS ── */
    .status-btn {
      cursor: pointer; border: none; border-radius: 8px;
      font-family: 'Jost', sans-serif; font-size: 11px;
      font-weight: 500; letter-spacing: 0.07em; text-transform: uppercase;
      padding: 6px 12px; transition: all 0.2s;
      display: inline-flex; align-items: center; gap: 5px;
    }
    .status-btn:hover { transform: translateY(-1px); filter: brightness(1.15); }
    .status-btn:active { transform: translateY(0); }

    .status-en-cours    { background: rgba(100,140,255,0.14); color: #8aaeff; border: 1px solid rgba(100,140,255,0.3); }
    .status-confirme    { background: rgba(201,153,42,0.15);  color: #c9992a; border: 1px solid rgba(201,153,42,0.35); }
    .status-expedition  { background: rgba(150,80,220,0.14);  color: #c080ff; border: 1px solid rgba(150,80,220,0.32); }
    .status-livre       { background: rgba(90,191,110,0.14);  color: #5abf6e; border: 1px solid rgba(90,191,110,0.32); }

    .status-btn.active.status-en-cours   { background: rgba(100,140,255,0.28); box-shadow: 0 4px 14px rgba(100,140,255,0.25); }
    .status-btn.active.status-confirme   { background: rgba(201,153,42,0.30);  box-shadow: 0 4px 14px rgba(201,153,42,0.22); }
    .status-btn.active.status-expedition { background: rgba(150,80,220,0.28);  box-shadow: 0 4px 14px rgba(150,80,220,0.22); }
    .status-btn.active.status-livre      { background: rgba(90,191,110,0.28);  box-shadow: 0 4px 14px rgba(90,191,110,0.22); }

    /* STATUS PROGRESS TRACK */
    @keyframes statusPop { 0%{transform:scale(0.6);opacity:0} 70%{transform:scale(1.15)} 100%{transform:scale(1);opacity:1} }
    .status-step-active { animation: statusPop 0.3s cubic-bezier(0.34,1.56,0.64,1) both; }

    .prod-card {
      transition: transform 0.3s cubic-bezier(0.34,1.56,0.64,1), box-shadow 0.3s ease;
      cursor: pointer;
    }
    .prod-card:hover {
      transform: translateY(-8px) scale(1.02);
      box-shadow: 0 24px 60px rgba(192,25,44,0.4), 0 0 0 1px rgba(192,25,44,0.25), inset 0 1px 0 rgba(255,255,255,0.05);
    }
    .btn-primary {
      background: linear-gradient(135deg, #8b0e1c, #c0192c, #d42035);
      border: none; cursor: pointer; font-family: 'Jost',sans-serif;
      font-weight: 500; letter-spacing: 0.08em; text-transform: uppercase;
      transition: all 0.25s; position: relative; overflow: hidden;
    }
    .btn-primary::before {
      content:''; position:absolute; inset:0;
      background: linear-gradient(135deg,rgba(255,255,255,0.1),transparent);
      opacity:0; transition:opacity 0.25s;
    }
    .btn-primary:hover::before { opacity:1; }
    .btn-primary:hover { transform:translateY(-1px); box-shadow:0 8px 24px rgba(192,25,44,0.5); }
    .btn-primary:active { transform:translateY(0); }

    .btn-or {
      background: linear-gradient(135deg, #8a6a10, #c9992a, #e0b84a);
      border: none; cursor: pointer; font-family: 'Jost',sans-serif;
      font-weight: 500; letter-spacing: 0.08em; text-transform: uppercase;
      transition: all 0.25s;
    }
    .btn-or:hover { transform:translateY(-1px); box-shadow:0 8px 24px rgba(201,153,42,0.5); }

    .nav-link {
      transition: all 0.2s; cursor:pointer;
      font-family:'Jost',sans-serif; font-size:12px; letter-spacing:0.1em;
      text-transform:uppercase; border:none; background:none;
    }
    .nav-link:hover { color: #f0c060 !important; }

    .cat-pill {
      cursor:pointer; transition:all 0.2s;
      font-family:'Jost',sans-serif; font-size:11px;
      letter-spacing:0.06em; text-transform:uppercase; border:none;
    }
    .cat-pill:hover { transform:translateY(-1px); }

    input, select, textarea {
      background: rgba(28,14,18,0.8) !important;
      color: #f2dde2 !important;
      border: 1px solid rgba(192,25,44,0.22) !important;
      border-radius: 8px; padding: 12px 16px;
      font-family: 'Jost',sans-serif; font-size:14px;
      width:100%; transition: border-color 0.2s, box-shadow 0.2s;
    }
    input::placeholder, textarea::placeholder { color: #5a3a44 !important; }
    input:focus, select:focus, textarea:focus {
      outline:none; border-color: rgba(201,153,42,0.5) !important;
      box-shadow: 0 0 0 3px rgba(192,25,44,0.1) !important;
    }
    select option { background:#1c0e12; }
    textarea { resize:vertical; min-height:80px; }

    ::-webkit-scrollbar { width:3px; height:3px; }
    ::-webkit-scrollbar-track { background: #0c0608; }
    ::-webkit-scrollbar-thumb { background: rgba(192,25,44,0.5); border-radius:99px; }

    .panier-slide { animation: slideIn 0.35s cubic-bezier(0.34,1.2,0.64,1); }
    .modal-up { animation: slideUp 0.4s cubic-bezier(0.34,1.2,0.64,1); }
    .card-in { animation: cardEntrance 0.5s cubic-bezier(0.34,1.2,0.64,1) both; }

    .star { transition: color 0.15s; cursor:pointer; }
    .star:hover { transform:scale(1.2); }

    .toast-notif { animation: toast 3s ease forwards; }

    .qty-btn {
      width:30px; height:30px; border-radius:50%; border:1px solid rgba(192,25,44,0.3);
      background:rgba(192,25,44,0.1); color:#e8677a; cursor:pointer; font-size:16px;
      display:flex; align-items:center; justify-content:center;
      transition:all 0.2s; font-family:'Jost',sans-serif;
    }
    .qty-btn:hover { background:rgba(192,25,44,0.25); transform:scale(1.1); }

    .scene-3d { perspective: 1000px; }
    .boutique-3d { transform-style: preserve-3d; animation: float 8s ease-in-out infinite; }
    .shelf { transform-style: preserve-3d; }
    .product-3d { animation: float2 6s ease-in-out infinite; }
    .orb { animation: orb 12s ease-in-out infinite; }

    .tab-btn { transition: all 0.2s; cursor:pointer; border:none; }
    .admin-row { transition: background 0.15s; }
    .admin-row:hover { background: rgba(255,255,255,0.03) !important; }

    .payment-card { transition: all 0.25s; cursor:pointer; border-radius:12px; }
    .payment-card:hover { transform:translateY(-2px); }
    .payment-card.selected {
      border-color: rgba(201,153,42,0.6) !important;
      background: rgba(201,153,42,0.08) !important;
    }

    .progress-step { transition: all 0.3s; }
    .wishlist-btn { transition: all 0.2s; cursor:pointer; border:none; background:none; }
    .wishlist-btn:hover { transform:scale(1.2); }
  `;
  document.head.appendChild(style);
};

