/* ═══════════════════════════════════════════════════════════════
   PAGE LOADER
═══════════════════════════════════════════════════════════════ */
function PageLoader({ label = "Chargement" }) {
  const [visible, setVisible] = useState(true);
  useEffect(() => {
    const t = setTimeout(() => setVisible(false), 1100);
    return () => clearTimeout(t);
  }, []);
  if (!visible) return null;
  return (
    <div className="page-loader" style={{ position:"fixed", inset:0, zIndex:9999,
      background:"linear-gradient(160deg,#1a0008 0%,#0c0608 50%,#100410 100%)",
      display:"flex", flexDirection:"column", alignItems:"center", justifyContent:"center", gap:20 }}>
      <div style={{ position:"relative", width:56, height:56, display:"flex", alignItems:"center", justifyContent:"center" }}>
        <div className="loader-ring" />
        <div className="loader-inner" />
        <div className="loader-center-dot" />
      </div>
      <p className="loader-text">{label}</p>
      <p style={{ fontFamily:"'Cormorant Garamond',serif", fontStyle:"italic", fontSize:"13px", color:"rgba(201,153,42,0.35)", letterSpacing:"0.15em" }}>✦ Princesse Plaisir ✦</p>
    </div>
  );
}

/* ═══════════════════════════════════════════════════════════════
   STATUS BUTTON GROUP (commandes)
═══════════════════════════════════════════════════════════════ */
function StatusButtons({ currentStatut, onChange }) {
  return (
    <div style={{ display:"flex", gap:"5px", flexWrap:"wrap" }}>
      {STATUTS_COMMANDE.map((s, idx) => {
        const isActive = currentStatut === s.id;
        const isPassed = STATUTS_COMMANDE.findIndex(x => x.id === currentStatut) > idx;
        return (
          <button
            key={s.id}
            className={`status-btn ${s.cls}${isActive ? " active" : ""}`}
            onClick={() => onChange(s.id)}
            style={{
              opacity: isPassed ? 0.55 : 1,
              textDecoration: isPassed ? "line-through" : "none",
            }}
          >
            <span style={{ fontSize:"10px" }}>{s.icon}</span>
            {s.label}
            {isActive && <span style={{ fontSize:"8px", marginLeft:2 }}>●</span>}
          </button>
        );
      })}
    </div>
  );
}

/* STATUS PROGRESS BAR */
function StatusProgress({ statut }) {
  const idx = STATUTS_COMMANDE.findIndex(s => s.id === statut);
  return (
    <div style={{ display:"flex", alignItems:"center", gap:0, width:"100%", marginTop:8 }}>
      {STATUTS_COMMANDE.map((s, i) => {
        const done = i <= idx;
        const active = i === idx;
        return (
          <div key={s.id} style={{ display:"flex", alignItems:"center", flex: i < STATUTS_COMMANDE.length - 1 ? 1 : "none" }}>
            <div
              className={active ? "status-step-active" : ""}
              style={{
                width: active ? 28 : 22, height: active ? 28 : 22,
                borderRadius:"50%",
                background: done
                  ? (active ? `linear-gradient(135deg,${C.rougeDark},${C.rouge})` : "rgba(192,25,44,0.35)")
                  : "rgba(255,255,255,0.05)",
                border: `1.5px solid ${done ? C.rouge : C.bordure}`,
                display:"flex", alignItems:"center", justifyContent:"center",
                fontSize: active ? 12 : 10,
                transition:"all 0.3s",
                flexShrink:0,
                boxShadow: active ? `0 0 14px rgba(192,25,44,0.5)` : "none",
              }}
            >
              {done ? (active ? s.icon : "✓") : ""}
            </div>
            {i < STATUTS_COMMANDE.length - 1 && (
              <div style={{
                flex:1, height:"2px", margin:"0 3px",
                background: i < idx
                  ? `linear-gradient(to right,${C.rougeDark},${C.rouge})`
                  : C.bordure,
                borderRadius:99, transition:"background 0.4s",
              }} />
            )}
          </div>
        );
      })}
    </div>
  );
}

